export interface Product {
  id: string;
  name: string;
  price: number;
  mrp: number;
  discount: number;
  fabric: string;
  color: string;
  occasion: string[];
  style: string;
  description: string;
  images: string[];
  rating: number;
  reviewCount: number;
  reviews: Review[];
  inventory: number;
  tags: string[];
  category: string;
  seller: string;
}

export interface Review {
  name: string;
  rating: number;
  text: string;
  date: string;
}

// Seeded random for SSR/client consistency
let seed = 42;
function sr(): number { seed = (seed * 16807) % 2147483647; return (seed - 1) / 2147483646; }
const pick = <T,>(a: T[]): T => a[Math.floor(sr() * a.length)];
const ri = (a: number, b: number) => Math.floor(sr() * (b - a + 1)) + a;

const REVIEWERS = ["Priya S.", "Anitha K.", "Meena R.", "Lakshmi V.", "Kavitha M.", "Deepa G.", "Sunita P.", "Radha N.", "Geeta B.", "Neha M.", "Anjali P.", "Divya R."];
const GOOD = ["Beautiful! Exactly as shown!", "Excellent quality, many compliments!", "Worth every rupee!", "Loved it! Will buy again.", "Premium quality, very impressed.", "Perfect for the occasion!", "Gorgeous! Highly recommend.", "Soft & comfortable.", "Amazing craftsmanship!", "So many compliments!"];
const OK = ["Good but color slightly different.", "Nice quality, slow delivery.", "Good overall.", "Beautiful but heavy.", "Good value."];
const BAD = ["Color faded after wash.", "Thinner than expected.", "Thread loosening."];

function reviews(n: number): Review[] {
  return Array.from({ length: n }, () => {
    const r = sr() > 0.15 ? ri(3, 5) : ri(1, 3);
    return { name: pick(REVIEWERS), rating: r, text: r >= 4 ? pick(GOOD) : r === 3 ? pick(OK) : pick(BAD), date: `2026-0${ri(1,3)}-${String(ri(1,28)).padStart(2,"0")}` };
  });
}

