const COLORS = ["Red", "Maroon", "Blue", "Navy", "Green", "Yellow", "Pink", "Orange", "Purple", "Beige", "Black", "Gold", "Teal", "Peach", "Wine", "Grey", "White", "Cream"];
const OCCASIONS = ["Wedding", "Festival", "Daily Wear", "Party", "Office", "Casual", "Puja", "Mehendi"];
const FABRICS_SAREE = ["Pure Silk", "Art Silk", "Cotton", "Chiffon", "Georgette", "Linen", "Tussar Silk", "Organza"];
const FABRICS_KURTI = ["Cotton", "Rayon", "Georgette", "Crepe", "Silk Blend", "Viscose"];
const FABRICS_KIDS = ["Cotton", "Polyester", "Cotton Blend", "Silk", "Net", "Satin"];
const FABRICS_JEWELRY = ["Gold Plated", "Silver Plated", "Kundan", "Meenakari", "Temple", "Oxidized Silver", "Pearl"];
const FABRICS_MEN = ["Cotton", "Linen", "Polyester", "Cotton Blend", "Denim", "Lycra"];
const SELLERS = ["Silk Palace", "Varanasi Handlooms", "Chennai Silks", "Nalli Silk", "Sundari Collections", "Mysore Creations", "Bengal Tant House", "Jaipur Textiles", "Kolkata Emporium", "Mumbai Fashion", "Delhi Couture", "Little Stars Kids", "Jewel House", "Men's Fashion Hub"];
const REGIONS_SAREE = ["Kanjivaram", "Banarasi", "Chanderi", "Cotton", "Chiffon", "Patola", "Bandhani", "Mysore Silk", "Paithani", "Linen", "Pochampally", "Tussar"];
const REGIONS_KURTI = ["Anarkali", "Straight", "A-Line", "Palazzo Set", "Embroidered", "Printed"];
const REGIONS_KIDS = ["Frock", "Dungaree", "Top & Bottom", "Ethnic Set", "Party Wear", "Casual Set"];
const REGIONS_JEWELRY = ["Necklace Set", "Choker", "Jhumka Set", "Bangles", "Maang Tikka Set", "Temple Set"];
const REGIONS_MEN = ["Formal", "Casual", "Party Wear", "Slim Fit", "Regular Fit", "Printed"];

function buildProducts(): Product[] {
  seed = 42;
  const out: Product[] = [];
  let id = 1;

  for (const item of SCRAPED) {
    // Use metadata from scraped data (verified by visual inspection)
    const color = item.color;
    const fabric = item.fabric;
    const region = item.style;
    const revs = reviews(ri(3, 8));
    const avg = Math.round((revs.reduce((s, r) => s + r.rating, 0) / revs.length) * 10) / 10;
    const mrp = Math.round(item.price * (1.2 + sr() * 0.3));

    out.push({
      id: `prod_${String(id++).padStart(4, "0")}`,
      name: item.name,
      price: item.price, mrp, discount: Math.round(((mrp - item.price) / mrp) * 100),
      fabric, color,
      occasion: item.occasions,
      style: sr() > 0.3 ? "Traditional" : sr() > 0.5 ? "Modern" : "Fusion",
      description: `${item.name} - Beautiful ${color.toLowerCase()} ${item.category.toLowerCase().slice(0, -1)} in premium ${fabric.toLowerCase()}. Perfect for ${item.occasions[0].toLowerCase()}. ${item.category === "Sarees" ? "Includes unstitched blouse piece." : ""} ${fabric} fabric with ${region.toLowerCase()} design.`,
      images: [item.img, SCRAPED[(id + 3) % SCRAPED.length].img, SCRAPED[(id + 7) % SCRAPED.length].img],
      rating: Math.min(5, Math.max(2.5, avg)),
      reviewCount: ri(15, 500),
      reviews: revs,
      inventory: ri(0, 30),
      tags: [region, fabric, item.category, ...item.occasions.slice(0, 1), ...(sr() > 0.6 ? ["Bestseller"] : []), ...(sr() > 0.7 ? ["New Arrival"] : []), ...(sr() > 0.8 ? ["Trending"] : [])],
      category: item.category,
      seller: pick(SELLERS),
    });

  }

  return out;
}

export const products = buildProducts();
export const allCategories = [...new Set(products.map(p => p.category))].sort();
export const subcategories = [...new Set(products.flatMap(p => p.tags.filter(t => !["Bestseller", "New Arrival", "Trending", "Sarees", "Kurtis", "Kids", "Jewelry", "Men", "Lehengas", "Dupattas", "Blouse Pieces", ...FABRICS_SAREE, ...FABRICS_KURTI, ...FABRICS_KIDS, ...FABRICS_JEWELRY, ...FABRICS_MEN, ...COLORS].includes(t))))].sort();
export const fabrics = [...new Set(products.map(p => p.fabric))].sort();
export const colors = [...new Set(products.map(p => p.color))].sort();
export const occasions = [...new Set(products.flatMap(p => p.occasion))].sort();
export const styles = [...new Set(products.flatMap(p => p.tags.slice(0, 1)))].sort();

